<?php
use Livewire\Component; use Illuminate\Support\Str;
new class extends Component { public ?\App\Models\Quiz $quiz = null; public string $title = ''; public string $description = ''; public string $type = 'assessment'; public ?int $duration_minutes = 10; public bool $is_published = false; public array $questions = [];
 public function mount(?\App\Models\Quiz $quiz = null): void { if ($quiz?->exists) { $this->quiz = $quiz->load('questions.options'); $this->title=$quiz->title; $this->description=$quiz->description ?? ''; $this->type=$quiz->type; $this->duration_minutes=$quiz->duration_minutes; $this->is_published=$quiz->is_published; $this->questions=$quiz->questions->map(fn($q)=>['question'=>$q->question,'options'=>$q->options->pluck('label')->all(),'correct'=>0])->all(); } if (!$this->questions) $this->addQuestion(); }
 public function addQuestion(): void { $this->questions[]=['question'=>'','options'=>['','','',''],'correct'=>0]; } public function removeQuestion(int $i): void { unset($this->questions[$i]); $this->questions=array_values($this->questions); }
 public function save(): void { $this->validate(['title'=>'required|max:120','description'=>'required','type'=>'required|in:quiz,assessment','questions'=>'required|min:1','questions.*.question'=>'required','questions.*.options.*'=>'required']); $quiz=$this->quiz ?? new \App\Models\Quiz; $quiz->fill(['title'=>$this->title,'slug'=>Str::slug($this->title).'-'.($this->quiz?->id ?? Str::lower(Str::random(5))),'description'=>$this->description,'type'=>$this->type,'duration_minutes'=>$this->duration_minutes,'is_published'=>$this->is_published,'interpretation_ranges'=>$this->type==='assessment'?[['min'=>0,'max'=>6,'label'=>'Perlu perhatian lebih'],['min'=>7,'max'=>12,'label'=>'Cukup terkelola'],['min'=>13,'max'=>20,'label'=>'Dalam kondisi baik']]:null]); $quiz->save(); $quiz->questions()->delete(); foreach($this->questions as $i=>$data){$q=$quiz->questions()->create(['question'=>$data['question'],'type'=>'single_choice','position'=>$i,'points'=>1]); foreach($data['options'] as $j=>$label){$q->options()->create(['label'=>$label,'value'=>$j+1,'is_correct'=>$this->type==='quiz' && $j===$data['correct'],'position'=>$j]);}} $this->redirectRoute('admin.dashboard'); }
}; ?>
<div><header class="admin-header"><div><a class="text-link" href="{{ route('admin.dashboard') }}">Kembali</a><h1>{{ $quiz ? 'Edit assessment' : 'Assessment baru' }}</h1></div><button class="button" wire:click="save">Simpan</button></header><section class="editor"><label>Judul<input wire:model="title"></label><label>Deskripsi<textarea wire:model="description" rows="3"></textarea></label><div class="form-grid"><label>Tipe<select wire:model="type"><option value="assessment">Assessment</option><option value="quiz">Quiz</option></select></label><label>Durasi (menit)<input wire:model="duration_minutes" type="number" min="1"></label></div><label class="check"><input wire:model="is_published" type="checkbox"> Publikasikan sekarang</label><h2>Pertanyaan</h2>@foreach($questions as $i=>$question)<article class="editor-question"><div class="question-heading"><strong>{{ $i + 1 }}</strong><button class="text-link danger" wire:click="removeQuestion({{ $i }})">Hapus</button></div><label>Pertanyaan<input wire:model="questions.{{ $i }}.question"></label>@foreach($question['options'] as $j=>$option)<label class="option-edit"><input wire:model="questions.{{ $i }}.options.{{ $j }}" placeholder="Pilihan {{ $j + 1 }}">@if($type === 'quiz')<input type="radio" wire:model="questions.{{ $i }}.correct" value="{{ $j }}" title="Jawaban benar">@endif</label>@endforeach</article>@endforeach<button class="button secondary" wire:click="addQuestion">+ Tambah pertanyaan</button></section></div>
